program RandomNumberDemo;

uses
  SysUtils; // Needed for Randomize, possibly IntToStr if not using WriteLn formatting

var
  min_val, max_val, random_num: Integer;
  random_float: Double; // Or Real, Extended

begin
  // Seed the random number generator (do this once at program start)
  Randomize;

  min_val := 1;
  max_val := 100;

  // Random(N) generates an integer between 0 and N-1.
  // To get range [min, max], use Random(max - min + 1) + min
  random_num := Random(max_val - min_val + 1) + min_val;

  WriteLn('Random Integer (', min_val, '-', max_val, '): ', random_num);

  // Random generates a float between 0.0 (inclusive) and 1.0 (exclusive)
  random_float := Random;
  WriteLn('Random Float [0.0 .. 1.0): ', random_float:0:5); // Format to 5 decimal places

