reverseString:
program ReverseStringDemo;

uses
  SysUtils, // Contains general utility functions
  StrUtils; // Contains ReverseString function (FPC specific)

function ReverseStringManual(const s: string): string;
var
  i, len: Integer;
  tempChar: Char;
begin
  // Note: Standard Pascal strings can be tricky. FPC's AnsiString is easier.
  // This assumes AnsiString or similar mutable string type.
  Result := s; // Make a copy
  len := Length(Result);
  if len <= 1 then
    Exit; // Nothing to reverse

  for i := 1 to len div 2 do
  begin
    tempChar := Result[i];
    Result[i] := Result[len - i + 1];
    Result[len - i + 1] := tempChar;
  end;
end;

var
  original, reversedManual, reversedUtil: string;

begin
  original := 'Hello World';

  // Method 1: Manual reversal
  reversedManual := ReverseStringManual(original);
  WriteLn('Original:       ', original);
  WriteLn('Reversed (Man): ', reversedManual);

  // Method 2: Using StrUtils.ReverseString (Easier, FPC only)
  reversedUtil := StrUtils.ReverseString(original);
  WriteLn('Reversed (Util):', reversedUtil);

  original := 'Pascal';
  WriteLn('Original:       ', original);
  WriteLn('Reversed (Util):', StrUtils.ReverseString(original));
end.

fibonacci:
program FibonacciDemo;

uses
  SysUtils;

// Procedure to print the first n Fibonacci numbers iteratively
procedure PrintFibonacci(n: Integer);
var
  i: Integer;
  t1, t2, nextTerm: QWord; // Use QWord (unsigned 64-bit) for larger range
                           // Or Int64 (signed 64-bit)
begin
  if n <= 0 then
  begin
    WriteLn('Number of terms must be positive.');
    Exit;
  end;

  t1 := 0;
  t2 := 1;

  Write('Fibonacci Sequence (first ', n, ' terms): ');

  for i := 1 to n do
  begin
    if i > 1 then
      Write(', ');

    if i = 1 then
    begin
      Write(t1);
    end
    else if i = 2 then
    begin
      Write(t2);
    end
    else
    begin
      // Basic overflow check (might not be perfect depending on exact type limits)
      // if (System.MaxQWord - t1 < t2) then begin ... end; - requires explicit limits
      nextTerm := t1 + t2; // FPC might check overflow in certain modes ($Q+)
      Write(nextTerm);
      t1 := t2;
      t2 := nextTerm;
    end;
  end;
  WriteLn; // Newline at the end
end;

begin
  PrintFibonacci(10);
  PrintFibonacci(93); // Around the limit for QWord/Int64
  // PrintFibonacci(94); // Likely overflows QWord/Int64
  PrintFibonacci(0);  // Test edge case
end.

factorial:
program FactorialDemo;

uses
  SysUtils;
  // Math; // Consider using Math unit for BigInteger if needed for n > 20

type
  // For very large numbers (n > 20), FPC has BigInteger in Math unit,
  // but for simplicity, we use QWord (unsigned 64-bit) here, limited to n <= 20.
  TFactorialResult = QWord; // Or Int64

// Function to calculate factorial iteratively
function Factorial(n: Cardinal): TFactorialResult; // Use Cardinal for non-negative input
var
  i: Cardinal;
  fact: TFactorialResult;
  // overflowCheck: Boolean;
begin
  // Factorial not defined for negative numbers (Cardinal prevents this)
  if n = 0 then
    Result := 1
  else
  begin
    if n > 20 then // Limit for 64-bit integers
    begin
       WriteLn('Warning: Factorial input ', n, ' > 20 will overflow 64-bit result.');
       // Optionally return 0 or raise an exception
    end;

    fact := 1;
    // overflowCheck := False;
    for i := 1 to n do
    begin
       // Simple overflow check before multiplication
       // if (System.MaxQWord div i < fact) then overflowCheck := True;
       // if overflowCheck then break;
       fact := fact * i; // FPC might check overflow ($Q+)
    end;
    Result := fact;
    // if overflowCheck then Result := 0; // Indicate overflow if checked
  end;
end;

var
  num: Cardinal;
  res: TFactorialResult;

begin
  num := 5;
  res := Factorial(num);
  WriteLn('Factorial of ', num, ' = ', res);

  num := 0;
  res := Factorial(num);
  WriteLn('Factorial of ', num, ' = ', res);

  num := 20; // Max for 64-bit
  res := Factorial(num);
  WriteLn('Factorial of ', num, ' = ', res);

  num := 21; // Will overflow 64-bit
  WriteLn('Attempting Factorial of ', num, '...');
  res := Factorial(num);
  WriteLn('Factorial of ', num, ' = ', res, ' (Result likely incorrect due to overflow)');

end.

primeCheck:
program PrimeCheckDemo;

uses
  SysUtils,
  Math; // For Sqrt function

// Function to check if a number is prime
function IsPrime(n: Int64): Boolean; // Use Int64 for larger range
var
  i, limit: Int64;
begin
  Result := False; // Assume not prime initially
  if n <= 1 then Exit; // Numbers <= 1 are not prime
  if n <= 3 then
  begin // 2 and 3 are prime
    Result := True;
    Exit;
  end;
  // Eliminate multiples of 2 and 3 early
  if (n mod 2 = 0) or (n mod 3 = 0) then Exit;

  // Check factors from 5 upwards, stepping by 6
  // Only need to check up to the square root of n
  limit := Trunc(Sqrt(n)); // Truncate the square root result
  i := 5;
  while i <= limit do
  begin
    if (n mod i = 0) or (n mod (i + 2) = 0) then
      Exit; // Found a factor, not prime
    i := i + 6;
  end;

  // If no divisors were found, it's prime
  Result := True;
end;

var
  num: Int64;
  numsToCheck: array[0..9] of Int64 = (0, 1, 2, 3, 4, 17, 25, 29, 97, 104729);
  i: Integer;

begin
  for i := Low(numsToCheck) to High(numsToCheck) do
  begin
    num := numsToCheck[i];
    if IsPrime(num) then
      WriteLn(num, ' is a prime number.')
    else
      WriteLn(num, ' is not a prime number.');
  end;
end.

