writeFile:
program WriteFileDemo;

// {$I-} // Optional: Disable IO checking for manual IOResult checks
uses
  SysUtils; // For exception handling (FPC)

var
  F: TextFile;
  Filename: string;
  i: Integer;

begin
  Filename := 'output_pascal.txt';

  // --- Overwrite Mode ('Rewrite') ---
  WriteLn('--- Writing (Overwrite) to ', Filename, ' ---');
  AssignFile(F, Filename);
  try
    Rewrite(F); // Create or overwrite the file for writing
    // {$I+} // Re-enable IO checking if using IOResult

    WriteLn(F, 'This line overwrites existing content.');
    WriteLn(F, 'Using Writeln from Pascal.');
    for i := 1 to 3 do
      WriteLn(F, 'Line number ', i);

    WriteLn('Content written successfully (overwrite).');

  except
    on E: EInOutError do
      WriteLn('Error writing to file (overwrite): ', E.Message);
  finally // FPC specific: Ensures CloseFile runs even if errors occur
     if Assigned(F) then CloseFile(F);
  end;


  // --- Append Mode ('Append') ---
  WriteLn;
  WriteLn('--- Appending to ', Filename, ' ---');
  AssignFile(F, Filename);
  try
    Append(F); // Open existing file for appending (or create if not found by some implementations)
               // Note: Standard Pascal Append requires the file to exist. FPC might create it.

    WriteLn(F, '--- Appended Content ---');
    WriteLn(F, 'This line was appended.');

    WriteLn('Content appended successfully.');

  except
     on E: EInOutError do
       WriteLn('Error appending to file: ', E.Message);
  finally
      if Assigned(F) then CloseFile(F);
  end;

  WriteLn;
  WriteLn('Check the content of ', Filename);

end.

