dateTime:
program DateTimeDemo;

uses
  SysUtils,   // Provides Now, Date, Time, FormatDateTime, etc.
  DateUtils;  // Provides additional date/time functions (like DayOfWeek)

var
  CurrentDateTime: TDateTime; // Combined date and time type
  CurrentDate: TDate;       // Date part only
  CurrentTime: TTime;       // Time part only
  FormattedString: string;

begin
  // 1. Get current date and time
  CurrentDateTime := Now;
  WriteLn('Current Date & Time (TDateTime): ', CurrentDateTime); // Raw numeric representation

  // 2. Get current date only
  CurrentDate := Date; // Function returns just the date part of Now
  WriteLn('Current Date (TDate): ', CurrentDate);

  // 3. Get current time only
  CurrentTime := Time; // Function returns just the time part of Now
  WriteLn('Current Time (TTime): ', CurrentTime);

  // 4. Formatting date/time - VERY flexible with FormatDateTime
  // Common Format Specifiers (case-sensitive):
  // yyyy: Year with century   yy: Year without century
  // mm: Month (01-12)         mmmm: Full month name
  // dd: Day (01-31)           dddd: Full weekday name
  // hh: Hour (12-hour, 01-12) Hh: Hour (24-hour, 00-23) - Note case difference
  // nn: Minute (00-59)        ss: Second (00-59)
  // zzz: Millisecond (000-999)
  // am/pm: AM/PM indicator

  FormattedString := FormatDateTime('yyyy-mm-dd Hh:nn:ss', CurrentDateTime);
  WriteLn('Formatted (YYYY-MM-DD HH:MM:SS): ', FormattedString);

  FormattedString := FormatDateTime('dddd, mmmm dd, yyyy', CurrentDateTime);
  WriteLn('Formatted (Long Date): ', FormattedString);

  FormattedString := FormatDateTime('hh:nn:ss am/pm', CurrentDateTime);
  WriteLn('Formatted (Time with AM/PM): ', FormattedString);

  // Predefined standard formats
  WriteLn('Formatted (General Date/Time): ', DateTimeToStr(CurrentDateTime)); // Locale dependent
  WriteLn('Formatted (Short Date): ', DateToStr(CurrentDate));         // Locale dependent
  WriteLn('Formatted (Short Time): ', TimeToStr(CurrentTime));         // Locale dependent

  // 5. Getting parts of the date/time (using DateUtils)
  WriteLn('Year: ', YearOf(CurrentDateTime));
  WriteLn('Month: ', MonthOf(CurrentDateTime));
  WriteLn('Day: ', DayOf(CurrentDateTime));
  WriteLn('Day of Week: ', DayOfWeek(CurrentDateTime), ' (1=Sunday, ..., 7=Saturday)'); // Depends on locale start day? Check docs. Often 1=Sun
  WriteLn('Hour: ', HourOf(CurrentDateTime));
  WriteLn('Minute: ', MinuteOf(CurrentDateTime));
  WriteLn('Second: ', SecondOf(CurrentDateTime));

  // 6. Epoch Time (Seconds since 1970-01-01 00:00:00 UTC) - More complex
  // Requires conversion to UTC and calculation. SysUtils has DateTimeToUnix/UnixToDateTime.
  try
    var EpochSeconds: Int64 := DateTimeToUnix(CurrentDateTime); // Converts assuming LOCAL time
    WriteLn('Seconds Since Epoch (Local Time Interpretation): ', EpochSeconds);
    // For true UTC epoch, convert TDateTime to UTC first if possible/needed
    // var UTCOffsetSeconds: Int64 := GetUTCOffsetSeconds(Now); // FPC specific? Needs checking
    // var UTCTime: TDateTime := IncSecond(Now, -UTCOffsetSeconds);
    // var EpochUTC: Int64 := DateTimeToUnix(UTCDateTime(Now)); // Needs UTCDateTime or similar
    // WriteLn('Seconds Since Epoch (Calculated UTC): ', EpochUTC);
  except
      on E: Exception do WriteLn('Error getting Unix time: ', E.Message);
  end;

end.

maxInArray:
program MaxInArrayDemo;

uses
  SysUtils; // For WriteLn, Integer types etc.

type
  // Define an array type (can be static or dynamic)
  TIntegerArray = array of Integer; // Dynamic array (FPC)
  // TStaticIntArray = array[1..10] of Integer; // Static array example

// Function to find the maximum value in a dynamic integer array
// Returns MinInt if array is empty
function FindMax(const arr: TIntegerArray): Integer;
var
  i: Integer;
  maxVal: Integer;
begin
  if Length(arr) = 0 then
  begin
    WriteLn('Error: Array is empty.');
    Result := System.MinInt; // Return smallest possible integer
    Exit;
  end;

  maxVal := arr[Low(arr)]; // Initialize with the first element (Low(arr) is 0 for dynamic arrays)
  // Loop from the second element onwards
  for i := Low(arr) + 1 to High(arr) do
  begin
    if arr[i] > maxVal then
      maxVal := arr[i];
  end;
  Result := maxVal;
end;

var
  numbers: TIntegerArray;
  emptyArr: TIntegerArray;
  maxResult: Integer;

begin
  // Initialize a dynamic array
  numbers := [10, 5, 42, 17, 8, 99, 32, -5, 0];
  // SetLength(numbers, 9);
  // numbers[0] := 10; numbers[1] := 5; ...

  Write('Array: ');
  for maxResult in numbers do // FPC supports for..in loop
     Write(maxResult, ' ');
  WriteLn;

  maxResult := FindMax(numbers);
  if maxResult <> System.MinInt then // Check if function returned valid max
    WriteLn('Maximum value: ', maxResult);

  // Test with empty array
  emptyArr := []; // Initialize empty dynamic array
  WriteLn;
  WriteLn('Testing empty array:');
  maxResult := FindMax(emptyArr);
   if maxResult = System.MinInt then
      WriteLn('Correctly handled empty array.');

end.
